mapper.select:

select 
from downstream_system_config


        and (system_code like #{keywordLike} or system_name like #{keywordLike})


        and owner_department_id = #{query.ownerDepartmentId}


        and status = #{query.status}


order by status desc, updated_at desc


select 
from downstream_service_config s
join downstream_system_config sys on s.system_id = sys.id


        and (sys.system_code like #{keywordLike}
        or sys.system_name like #{keywordLike}
        or s.service_code like #{keywordLike}
        or s.service_name like #{keywordLike}
        or s.endpoint like #{keywordLike})


        and sys.system_code = #{query.systemCode}


        and sys.owner_department_id = #{query.ownerDepartmentId}


        and s.service_type = #{query.serviceType}


        and s.enabled = '1'


        and s.enabled = '0'


order by sys.system_code asc, s.enabled desc, s.updated_at desc

mapper.insert:
insert into downstream_system_config (
    id, system_code, system_name, owner_department_id, default_auth_mode,
    default_timeout_seconds, default_retry_count, status, created_at, updated_at
) values (
    #{id}, #{systemCode}, #{systemName}, #{ownerDepartmentId}, #{defaultAuthMode},
    #{defaultTimeoutSeconds}, #{defaultRetryCount}, #{status}, #{createdAt}, #{updatedAt}
)

insert into downstream_service_config (
    id, system_id, service_code, service_name, purpose, service_type, endpoint,
    http_method, auth_mode, timeout_seconds, retry_count, response_success_rule,
    enabled, created_at, updated_at
) values (
    #{id}, #{systemId}, #{serviceCode}, #{serviceName}, #{purpose}, #{serviceType}, #{endpoint},
    #{httpMethod}, #{authMode}, #{timeoutSeconds}, #{retryCount}, #{responseSuccessRule},
    #{enabled}, #{createdAt}, #{updatedAt}
)
